import React, { useState, useMemo } from 'react';
import { DataConnection, BuilderPage } from '../../types';
import WindowPanel from '../WindowPanel';

interface CodeEditorProps {
  builderPages: BuilderPage[];
  activeBuilderPageId: string;
  dataConnections: DataConnection;
  onBuilderPagesChange: (pages: BuilderPage[]) => void;
}

const CodeEditor: React.FC<CodeEditorProps> = ({
  builderPages,
  activeBuilderPageId,
  dataConnections,
  onBuilderPagesChange
}) => {
  const [selectedWindow, setSelectedWindow] = useState<string | null>(null);

  // Helper functions with memoization
  const getCurrentBuilderPage = useMemo((): BuilderPage => {
    return builderPages.find(p => p.id === activeBuilderPageId) || builderPages[0];
  }, [builderPages, activeBuilderPageId]);

  const windows = useMemo(() => getCurrentBuilderPage.windows, [getCurrentBuilderPage]);

  const selectedWindowData = useMemo(() => {
    return selectedWindow ? windows.find(w => w.id === selectedWindow) : null;
  }, [windows, selectedWindow]);

  // Handle window code update
  const handleCodeChange = (code: string) => {
    if (!selectedWindow) return;
    
    const updatedPages = builderPages.map(page => {
      if (page.id !== activeBuilderPageId) return page;
      
      return {
        ...page,
        windows: page.windows.map(window => {
          if (window.id !== selectedWindow) return window;
          return { ...window, jsCode: code };
        })
      };
    });
    
    onBuilderPagesChange(updatedPages);
  };

  return (
    <div style={{ 
      flex: 1, 
      backgroundColor: '#1e1e1e',
      fontFamily: '"Segoe UI", "Arial", sans-serif',
      display: 'flex',
      height: '100%',
      color: '#e0e0e0'
    }}>
      {/* Left Panel - Window List */}
      <div style={{
        width: '220px',
        backgroundColor: '#252526',
        borderRight: '1px solid #3e3e42',
        display: 'flex',
        flexDirection: 'column',
        padding: '12px',
        overflow: 'auto'
      }}>
        <h3 style={{ margin: '0 0 12px 0', fontSize: '13px', fontWeight: '600', color: '#cccccc', textTransform: 'uppercase', letterSpacing: '0.5px' }}>
          Windows
        </h3>
        
        <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
          {windows.map(window => (
            <div
              key={window.id}
              onClick={() => setSelectedWindow(window.id)}
              style={{
                padding: '8px 10px',
                backgroundColor: selectedWindow === window.id ? '#094771' : '#3c3c3c',
                border: selectedWindow === window.id ? '1px solid #0e639c' : '1px solid #3e3e42',
                borderRadius: '3px',
                cursor: 'pointer',
                fontSize: '12px',
                transition: 'all 0.2s ease',
                color: selectedWindow === window.id ? '#4fc1ff' : '#cccccc'
              }}
              onMouseEnter={(e) => {
                if (selectedWindow !== window.id) {
                  e.currentTarget.style.backgroundColor = '#464646';
                }
              }}
              onMouseLeave={(e) => {
                if (selectedWindow !== window.id) {
                  e.currentTarget.style.backgroundColor = '#3c3c3c';
                }
              }}
            >
              <div style={{ fontWeight: '500', marginBottom: '2px' }}>
                {window.title}
              </div>
              <div style={{ fontSize: '10px', color: '#858585' }}>
                {window.type}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Middle Panel - Code Execution */}
      <div style={{
        flex: 1,
        backgroundColor: '#1e1e1e',
        borderRight: '1px solid #3e3e42',
        display: 'flex',
        flexDirection: 'column',
        overflow: 'hidden'
      }}>
        <div style={{
          padding: '8px 12px',
          backgroundColor: '#2d2d30',
          borderBottom: '1px solid #3e3e42',
          fontSize: '12px',
          fontWeight: '500',
          color: '#cccccc'
        }}>
          {selectedWindowData ? `Execution: ${selectedWindowData.title}` : 'Select a window'}
        </div>
        
        <div style={{
          flex: 1,
          overflow: 'auto',
          backgroundColor: '#1e1e1e'
        }}>
          {selectedWindowData && (
            <WindowPanel
              window={selectedWindowData}
              onUpdate={() => {}}
              dataConnections={dataConnections}
              isEditing={false}
            />
          )}
        </div>
      </div>

      {/* Right Panel - Code Editor */}
      <div style={{
        width: '380px',
        backgroundColor: '#1e1e1e',
        display: 'flex',
        flexDirection: 'column',
        borderLeft: '1px solid #3e3e42'
      }}>
        <div style={{
          padding: '8px 12px',
          backgroundColor: '#2d2d30',
          borderBottom: '1px solid #3e3e42',
          fontSize: '12px',
          fontWeight: '500',
          color: '#cccccc'
        }}>
          Code Editor
        </div>
        
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
          {selectedWindowData ? (
            <>
              <textarea
                value={selectedWindowData.jsCode || ''}
                onChange={(e) => handleCodeChange(e.target.value)}
                style={{
                  flex: 1,
                  border: 'none',
                  padding: '12px',
                  fontSize: '12px',
                  fontFamily: '"Courier New", monospace',
                  backgroundColor: '#252526',
                  color: '#d4d4d4',
                  resize: 'none',
                  outline: 'none'
                }}
              />
            </>
          ) : (
            <div style={{
              flex: 1,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              color: '#6a6a6a',
              fontSize: '12px'
            }}>
              Select a window to edit code
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default CodeEditor;
